module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

localparam IDLE = 2'b00;
localparam STATE1 = 2'b01;
localparam STATE2 = 2'b10;
localparam STATE3 = 2'b11;

reg [1:0] state, next_state;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= IDLE;
    end else begin
        state <= next_state;
    end
end

always @(*) begin
    case (state)
        IDLE: begin
            if (data_in == 1'b1) begin
                next_state = STATE1;
            end else begin
                next_state = IDLE;
            end
        end

        STATE1: begin
            if (data_in == 1'b0) begin
                next_state = STATE2;
            end else begin
                next_state = STATE1;
            end
        end

        STATE2: begin
            if (data_in == 1'b1) begin
                next_state = STATE3;
            end else begin
                next_state = IDLE;
            end
        end

        STATE3: begin
            if (data_in == 1'b0) begin
                next_state = IDLE;
            end else begin
                next_state = STATE1;
            end
        end

        default: begin
            next_state = IDLE;
        end
    endcase

    if ((state == STATE3) && (data_in == 1'b0)) begin
        data_out = 1'b1;
    end else begin
        data_out = 1'b0;
    end
end
endmodule
